import React, { useState } from "react";

export default function Profile() {
  const [postContent, setPostContent] = useState("");
  const [posts, setPosts] = useState([]);

  // Mỗi post có thể có comments: {input: "", list: []}
  const [comments, setComments] = useState([]);

  const handleAddPost = () => {
    if (!postContent.trim()) return;

    const newPost = {
      text: postContent,
      time: new Date().toLocaleString(),
      images: [
        "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nwti4bgy_expires_30_days.png",
        "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/3cxpt7rg_expires_30_days.png",
      ],
    };

    setPosts([newPost, ...posts]);
    setComments([{ input: "", list: [] }, ...comments]);
    setPostContent("");
  };

  return (
    <div className="flex flex-col items-center bg-[#F4FAFF] min-h-screen pt-[40px] px-6 ml-[72px]">
      <div className="flex flex-col items-center gap-8 w-full max-w-[1060px]">

        {/* --- Thông tin người dùng --- */}
        <div className="bg-[#A2D3FF] w-full p-6 rounded-2xl shadow-lg">
          <div className="flex flex-col items-center bg-[#F7FFFF] p-8 rounded-2xl relative overflow-hidden">
            <div className="flex flex-col items-center z-10">
              <span className="text-black text-3xl font-semibold mb-3">Nguyễn Văn A</span>
              <div className="flex items-center gap-5">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/tb3lhluz_expires_30_days.png"
                  alt="avatar"
                  className="w-[80px] h-[75px] rounded-full object-cover"
                />
                <div className="flex flex-col items-center">
                  <span className="text-black text-sm mt-2">“Không thời gian – Dương Domic”</span>
                </div>
              </div>
            </div>
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ths2znj7_expires_30_days.png"
              alt="decoration"
              className="absolute top-[10px] bottom-0 left-4 w-[180px] h-[160px] opacity-80"
            />
          </div>
        </div>

        {/* --- Thông tin chi tiết --- */}
        <div className="bg-[#A2D3FF] w-full p-6 rounded-2xl shadow-lg">
          <div className="flex justify-center gap-6 mb-4">
            <div className="flex flex-col items-center bg-[#FFDEF8] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Học vấn</span>
              <select className="w-[160px] bg-white text-gray-700 text-sm rounded-md px-2 py-1 focus:outline-none focus:ring-2 focus:ring-purple-300">
                <option value="danghoc">Đang học</option>
                <option value="totnghiep">Đã tốt nghiệp</option>
                <option value="tamnghi">Tạm nghỉ học</option>
                <option value="baoluu">Bảo lưu</option>
                <option value="chuahoc">Chưa học đại học</option>
              </select>
            </div>
            <div className="flex flex-col items-center bg-[#FFE9FA] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Những điều về tuii</span>
            </div>
            <div className="flex flex-col items-center bg-[#C6E1FF] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">#hashtag</span>
            </div>
          </div>

          <div className="flex justify-center gap-6">
            <div className="flex flex-col items-center bg-[#C6E1FF] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Khoa</span>
              <select className="w-[160px] bg-white text-gray-700 text-sm rounded-md px-2 py-1 focus:outline-none focus:ring-2 focus:ring-blue-300">
                <option value="CNTT">Công nghệ thông tin</option>
                <option value="QTKD">Quản trị kinh doanh</option>
                <option value="NNA">Ngôn ngữ Anh</option>
              </select>
            </div>
            <div className="flex flex-col items-center bg-[#FFDEF8] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Nơi ở</span>
              <select className="w-[160px] bg-white text-gray-700 text-sm rounded-md px-2 py-1 focus:outline-none focus:ring-2 focus:ring-pink-300">
                <option value="HCM">TP. Hồ Chí Minh</option>
                <option value="HN">Hà Nội</option>
              </select>
            </div>
            <div className="flex flex-col items-center bg-[#FFE9FA] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Quê quán</span>
              <select className="w-[160px] bg-white text-gray-700 text-sm rounded-md px-2 py-1 focus:outline-none focus:ring-2 focus:ring-purple-300">
                <option value="BD">Bình Dương</option>
                <option value="HCM">TP. Hồ Chí Minh</option>
              </select>
            </div>
          </div>
        </div>

        {/* --- Thêm bài đăng --- */}
        <div className="bg-white w-full p-6 rounded-2xl shadow-lg mt-[-12px]">
          <h2 className="text-xl font-semibold text-gray-800 mb-3">Bài đăng</h2>
          <textarea
            value={postContent}
            onChange={(e) => setPostContent(e.target.value)}
            placeholder="Viết điều gì đó về bạn..."
            className="w-full p-3 border border-gray-300 rounded-lg resize-none text-black"
            rows="3"
          />
          <div className="flex justify-end mt-3">
            <button
              onClick={handleAddPost}
              className="bg-blue-500 hover:bg-blue-600 text-white px-5 py-2 rounded-lg transition-all"
            >
              Đăng
            </button>
          </div>
        </div>

        {/* --- Danh sách bài đăng --- */}
        {posts.map((post, i) => (
          <div key={i} className="flex flex-col bg-[#A2D3FF] w-full max-w-[1000px] p-4 rounded-[10px] gap-4 mt-4">
            {/* Header bài post */}
            <div className="flex items-center gap-4">
              <img
                src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/oadiyd0v_expires_30_days.png"
                className="w-[58px] h-[51px] rounded-full"
                alt="avatar"
              />
              <div className="flex flex-col">
                <span className="text-black text-xl">Nguyễn Văn A</span>
                <span className="text-black text-base">công khai</span>
              </div>
            </div>

            {/* Hình ảnh */}
            <div className="flex gap-4">
              {post.images.map((img, idx) => (
                <img key={idx} src={img} className="w-1/2 rounded-lg" alt={`post-${idx}`} />
              ))}
            </div>

            {/* Bình luận */}
            <div className="flex items-center gap-2 mt-2">
              <img
                src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/gyfive3m_expires_30_days.png"
                className="w-[39px] h-[45px] rounded-[10px] cursor-pointer transition-transform duration-300"
                alt="like"
                onClick={(e) => {
                  const target = e.currentTarget;
                  target.classList.add("scale-up");
                  setTimeout(() => target.classList.remove("scale-up"), 300);
                }}
              />
              <input
                placeholder="Bình luận"
                value={comments[i]?.input || ""}
                onChange={(e) => {
                  const newComments = [...comments];
                  newComments[i].input = e.target.value;
                  setComments(newComments);
                }}
                className="flex-1 py-2 px-4 rounded-lg text-black border-0"
              />
              <button
                className="bg-blue-500 text-white px-3 py-1 rounded-lg"
                onClick={() => {
                  if (!comments[i]?.input?.trim()) return;
                  const newComments = [...comments];
                  if (!newComments[i].list) newComments[i].list = [];
                  newComments[i].list.push(newComments[i].input);
                  newComments[i].input = "";
                  setComments(newComments);
                }}
              >
                Gửi
              </button>
            </div>

            {/* Danh sách bình luận */}
            {comments[i]?.list?.length > 0 && (
              <div className="mt-2 ml-12 flex flex-col gap-1">
                {comments[i].list.map((cmt, idx) => (
                  <span key={idx} className="text-black text-sm bg-white px-2 py-1 rounded-lg">
                    {cmt}
                  </span>
                ))}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
